// Plaud entrega DOS adjuntos: transcripción.txt y resumen.txt
// Los separa por NOMBRE y los decodifica con el helper de n8n (evita corrupción).
const item = $input.first();
const binarios = item.binary || {};
let transcripcion = null;
let resumen = null;
for (const clave of Object.keys(binarios)) {
  const nombre = (binarios[clave].fileName || '').toLowerCase();
  const buffer = await this.helpers.getBinaryDataBuffer(0, clave);
  const contenido = buffer.toString('utf-8');
  if (nombre.includes('transcrip')) {
    transcripcion = contenido;
  } else if (nombre.includes('resumen')) {
    resumen = contenido;
  }
}
if (!transcripcion) throw new Error('No se encontró el adjunto de transcripción');
if (!resumen) throw new Error('No se encontró el adjunto de resumen');

const asunto = item.json.subject || '';
// Formato nuevo de Plaud: "[Plaud-AutoFlow] 2026-06-24 10:31:45" → captura YYYY-MM-DD directo
let fechaReunion = null;
const fechaCompleta = asunto.match(/(\d{4})-(\d{2})-(\d{2})/);  // busca 2026-06-24
if (fechaCompleta) {
  fechaReunion = `${fechaCompleta[1]}-${fechaCompleta[2]}-${fechaCompleta[3]}`;  // ya es YYYY-MM-DD
} else {
  // Compatibilidad con formato viejo: "06-18" (MM-DD)
  const fechaCorta = asunto.match(/(\d{2})-(\d{2})/);
  const anio = new Date(item.json.date || Date.now()).getFullYear();
  fechaReunion = fechaCorta ? `${anio}-${fechaCorta[1]}-${fechaCorta[2]}` : null;
}

return [{
  json: {
    subject: asunto,
    fecha_reunion: fechaReunion,
    transcripcion: transcripcion,
    resumen: resumen,
    cliente_id: 'client_demo',
    cliente_nombre: 'Empresa Demo S.L.',
    cliente_ceo: 'Persona A'
  }
}];

// Convierte el resumen de Plaud (markdown) para el correo (HTML) y para el DOCX (texto plano)
const item = $input.first();
const original = item.json.resumen || '';
// Elimina las referencias a imágenes markdown que mete Plaud: ![PLAUD NOTE](...png)
const limpioOriginal = original.replace(/!\[[^\]]*\]\([^)]*\)/g, '').trim();
const asunto = String(item.json.asunto || '');
// Formato nuevo de Plaud: "[Plaud-AutoFlow] 2026-06-24 10:36:02" → captura YYYY-MM-DD
let fechaES = '';
const mNueva = asunto.match(/(\d{4})-(\d{2})-(\d{2})/);  // busca 2026-06-24
if (mNueva) {
  fechaES = `${mNueva[3]}/${mNueva[2]}/${mNueva[1]}`;  // "24/06/2026"
} else {
  // Respaldo formato viejo "06-22"
  const mVieja = asunto.match(/(\d{2})-(\d{2})/);
  const anio = String(item.json.fecha_reunion || '').slice(0, 4) || '2026';
  fechaES = mVieja ? `${mVieja[2]}/${mVieja[1]}/${anio}` : '';
}
// Hora de la reunión desde el asunto: "...10:36:02" → "10-36"
const mHora = asunto.match(/(\d{2}):(\d{2}):(\d{2})/);
const horaArchivo = mHora ? `${mHora[1]}h${mHora[2]}` : '';  // "10h36"
// ===== 1) HTML BONITO PARA EL CORREO =====
let texto = limpioOriginal;
texto = texto.replace(/\\n/g, '\n');
texto = texto.replace(/^###\s*(.+)$/gm, '<h3 style="color:#2c5f2d;margin:18px 0 8px;">$1</h3>');
texto = texto.replace(/^##\s*(.+)$/gm, '<h2 style="color:#2c5f2d;margin:20px 0 10px;">$1</h2>');
texto = texto.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
texto = texto.replace(/^[-*]\s+(.+)$/gm, '<li style="margin:4px 0;">$1</li>');
texto = texto.replace(/(<li[\s\S]*?<\/li>)(?!\s*<li)/g, '<ul style="margin:8px 0;padding-left:22px;">$1</ul>');
texto = texto.replace(/\n{2,}/g, '</p><p style="margin:10px 0;line-height:1.6;">');
texto = texto.replace(/\n/g, '<br>');
const html = `
<div style="font-family:Arial,sans-serif;color:#333;max-width:640px;margin:0 auto;padding:20px;">
  <div style="border-bottom:3px solid #2c5f2d;padding-bottom:12px;margin-bottom:16px;">
    <h1 style="color:#2c5f2d;font-size:20px;margin:0;">Empresa Demo S.L. — Resumen de reunión</h1>
    <p style="color:#888;font-size:13px;margin:4px 0 0;">${fechaES}</p>
  </div>
  <p style="margin:10px 0;line-height:1.6;">${texto}</p>
  <div style="border-top:1px solid #ccc;margin-top:28px;padding-top:12px;">
    <p style="color:#2c5f2d;font-weight:bold;font-size:14px;margin:0 0 4px;">¿Algo que corregir o añadir?</p>
    <p style="color:#666;font-size:13px;margin:0;">Responde a este correo en lenguaje normal (por ejemplo: «donde dice X es Y»). Lo registramos y se aplicará en los siguientes resúmenes (semanal, mensual, etc.).</p>
  </div>
</div>`;
let limpio = limpioOriginal;
limpio = limpio.replace(/\\n/g, '\n');           // normaliza saltos a reales
// Títulos (### / ## / #) → MAYÚSCULAS con línea en blanco antes
limpio = limpio.replace(/^#{1,6}\s*(.+)$/gm, (m, t) => '\n' + t.toUpperCase().trim());
limpio = limpio.replace(/\*\*(.+?)\*\*/g, '$1'); // quita ** negritas
limpio = limpio.replace(/\*(.+?)\*/g, '$1');     // quita * cursivas
limpio = limpio.replace(/^\s*[-*]\s+/gm, '• ');  // viñetas como •
limpio = limpio.replace(/\n{3,}/g, '\n\n');      // máximo una línea en blanco seguida
limpio = limpio.trim();
return [{
  json: {
    ...item.json,
    resumen_html: html,
    resumen_limpio: limpio,
    fecha_es: fechaES,
    fecha_archivo: fechaES.replaceAll('/', '-'),
    hora_archivo: horaArchivo
  }
}];
